ader", "labelDefinition": "该企业所采用的技术或技术路线已经或正在成为该行业的主流趋势，相比同行业具有较高的市场竞争力和创新能力。", "labelName": "技术布局行业领先"}, {"labelCode": "has_patent_green", "labelDefinition": "该企业拥有以绿色低碳技术为发明主题的专利。绿色低碳技术是指通过传统能源清洁利用、节能增效、新能源利用和温室气体捕集利用封存等实现减碳、零碳和负碳效果的有关技术。", "labelName": "拥有绿色低碳技术"}, {"labelCode": "ability_innovation", "labelDefinition": "根据企业公开的和国家专利局网站公示的专利信息显示，本企业拥有突出的工艺创新能力，在生产过程中，通过设计和实施新的生产工艺或改进现有工艺，实现生产效率和产品质量的提高，也降低了生产成本；同时也表明了本企业在技术水平、技术人才、创新发展等方面拥有较强的企业实力。", "labelName": "拥有工艺创新能力", "labelTranslateName": "工艺/技术创新能力突出"}, {"labelCode": "esg_certificate_e", "labelDefinition": "该企业拥有环保绿色相关资质认证。", "labelName": "拥有绿色资质", "labelTranslateName": "拥有绿色资质"}, {"labelCode": "own_independent_brand", "labelDefinition": "该企业拥有NANFU南孚、南孚、南孚电池、NANFU 南孚自主品牌。", "labelName": "拥有自主品牌"}, {"labelCode": "brand_amount_ranking", "labelDefinition": "该企业旗下所拥有自主品牌的数量位于同行业前列。", "labelName": "旗下品牌同行前5%"}, {"labelCode": "college_employment_contribution", "labelDefinition": "据公开网络招聘信息显示，该企业在近1年内有发布过大学生就业岗位，助力大学生就业。", "labelName": "大学生就业贡献", "labelTranslateName": "欢迎应届生应聘"}], "showTypeUrl": "https://imgjl.51jobcdn.com/cdn/51job/FileService/FileUpload/image/20250520/ptcard_128e85b893a640e8940c74c70daada54.png", "showTypeUrlDark": "https://imgjl.51jobcdn.com/cdn/51job/FileService/FileUpload/image/20251208/a7401c7dc5b291eef900ff6b78327e18_f2a16bd811034ae78dea2e01b9945aee.png", "smallHrLogoUrl": "https://img01.51jobcdn.com/imehire/userportrait/default/li_portrait_female_005_small.png?v=20260317", "term": "0", "termStr": "全职", "triggerBatchDeliver": true, "updateDateTime": "2026-04-15 14:54:40", "userInteractionOnlineLabel": 2, "workAreaCode": "110800", "workYear": "10", "workYearString": "无需经验"}

